python3 -c "
import re, os
errors=[]
for f in sorted(os.listdir('.arkpilot/designs/')):
    if f.startswith('page-') and f.endswith('.html'):
        path=os.path.join('.arkpilot/designs/', f)
        text=open(path).read()
        svgs=re.findall(r'<svg[^>]*>(.*?)</svg>', text, re.S)
        for s in svgs:
            if not re.search(r'<title>', s):
                errors.append(f'{f}: svg missing <title>')
                break
        if 'data-page-id' not in text:
            errors.append(f'{f}: missing data-page-id')
if errors:
    for e in errors: print(e)
else:
    print('All page HTMLs have data-page-id and titled SVGs')
"
